using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders; using verii_metivon_api.Modules.TradeOperations.Domain.Entities;
namespace verii_metivon_api.Modules.TradeOperations.Infrastructure.Persistence.Configurations;
public sealed class TradeDossierConfiguration:IEntityTypeConfiguration<TradeDossier>{public void Configure(EntityTypeBuilder<TradeDossier>b){b.ToTable("RII_TRADE_DOSSIERS");b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>x.DossierNumber).IsUnique().HasFilter("[IsDeleted] = 0");b.HasIndex(x=>new{x.Direction,x.Status,x.BranchId});b.Property(x=>x.DossierNumber).HasMaxLength(50).IsRequired();b.Property(x=>x.CurrencyCode).HasMaxLength(3).IsUnicode(false).IsRequired();b.Property(x=>x.IncotermCode).HasMaxLength(10).IsUnicode(false).IsRequired();b.Property(x=>x.PaymentMethodCode).HasMaxLength(30);b.Property(x=>x.DeliveryMethodCode).HasMaxLength(30);b.Property(x=>x.CustomsOfficeCode).HasMaxLength(20);b.Property(x=>x.MasterTransportDocumentNumber).HasMaxLength(80);b.Property(x=>x.HouseTransportDocumentNumber).HasMaxLength(80);b.Property(x=>x.ContainerNumber).HasMaxLength(30);b.Property(x=>x.VehicleOrVoyageNumber).HasMaxLength(50);b.Property(x=>x.PortOfLoadingCode).HasMaxLength(20);b.Property(x=>x.PortOfDischargeCode).HasMaxLength(20);b.Property(x=>x.CountryOfDispatchCode).HasMaxLength(2).IsUnicode(false);b.Property(x=>x.Notes).HasMaxLength(2000);b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.BusinessPartner).WithMany().HasForeignKey(x=>x.BusinessPartnerId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class CustomsDeclarationConfiguration:IEntityTypeConfiguration<CustomsDeclaration>{public void Configure(EntityTypeBuilder<CustomsDeclaration>b){b.ToTable("RII_CUSTOMS_DECLARATIONS");b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>x.DeclarationNumber).IsUnique().HasFilter("[IsDeleted] = 0");b.HasIndex(x=>x.RegistrationNumber).HasFilter("[RegistrationNumber] IS NOT NULL AND [IsDeleted] = 0");b.Property(x=>x.DeclarationNumber).HasMaxLength(30).IsRequired();b.Property(x=>x.RegistrationNumber).HasMaxLength(30);b.Property(x=>x.RegimeCode).HasMaxLength(10).IsRequired();b.Property(x=>x.CustomsOfficeCode).HasMaxLength(20).IsRequired();b.Property(x=>x.CustomsExchangeRate).HasPrecision(24,8);b.Property(x=>x.TotalTaxes).HasPrecision(24,8);b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.TradeDossier).WithMany(x=>x.Declarations).HasForeignKey(x=>x.TradeDossierId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class CustomsDeclarationLineConfiguration:IEntityTypeConfiguration<CustomsDeclarationLine>{public void Configure(EntityTypeBuilder<CustomsDeclarationLine>b){b.ToTable("RII_CUSTOMS_DECLARATION_LINES",t=>t.HasCheckConstraint("CK_RII_CUSTOMS_DECLARATION_LINES_RELEASED","[ReleasedQuantity] >= 0 AND [ReleasedQuantity] <= [Quantity]"));b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>new{x.CustomsDeclarationId,x.LineNumber}).IsUnique();b.Property(x=>x.GtipCode).HasMaxLength(20).IsRequired();b.Property(x=>x.CountryOfOriginCode).HasMaxLength(2).IsUnicode(false);foreach(var p in new[]{nameof(CustomsDeclarationLine.Quantity),nameof(CustomsDeclarationLine.NetWeight),nameof(CustomsDeclarationLine.GrossWeight),nameof(CustomsDeclarationLine.CustomsValue),nameof(CustomsDeclarationLine.CustomsDuty),nameof(CustomsDeclarationLine.VatAmount),nameof(CustomsDeclarationLine.ReleasedQuantity)})b.Property(p).HasPrecision(24,8);b.HasOne(x=>x.CustomsDeclaration).WithMany(x=>x.Lines).HasForeignKey(x=>x.CustomsDeclarationId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.Product).WithMany().HasForeignKey(x=>x.ProductId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class TradeDossierStatusHistoryConfiguration:IEntityTypeConfiguration<TradeDossierStatusHistory>{public void Configure(EntityTypeBuilder<TradeDossierStatusHistory>b){b.ToTable("RII_TRADE_DOSSIER_STATUS_HISTORY");b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>new{x.TradeDossierId,x.OccurredAt});b.Property(x=>x.ReasonCode).HasMaxLength(40);b.Property(x=>x.Notes).HasMaxLength(1000);b.HasOne(x=>x.TradeDossier).WithMany(x=>x.StatusHistory).HasForeignKey(x=>x.TradeDossierId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class CustomsDeclarationStatusHistoryConfiguration:IEntityTypeConfiguration<CustomsDeclarationStatusHistory>{public void Configure(EntityTypeBuilder<CustomsDeclarationStatusHistory>b){b.ToTable("RII_CUSTOMS_DECLARATION_STATUS_HISTORY");b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>new{x.CustomsDeclarationId,x.OccurredAt});b.Property(x=>x.ReasonCode).HasMaxLength(40);b.Property(x=>x.Notes).HasMaxLength(1000);b.HasOne(x=>x.CustomsDeclaration).WithMany(x=>x.StatusHistory).HasForeignKey(x=>x.CustomsDeclarationId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class TradeDocumentLinkConfiguration:IEntityTypeConfiguration<TradeDocumentLink>{public void Configure(EntityTypeBuilder<TradeDocumentLink>b){b.ToTable("RII_TRADE_DOCUMENT_LINKS");b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>new{x.TradeDossierId,x.LinkType,x.SourceId,x.SourceLineId}).IsUnique().HasFilter("[IsDeleted] = 0");b.Property(x=>x.LinkedQuantity).HasPrecision(24,8);b.Property(x=>x.ReferenceNumber).HasMaxLength(80);b.HasOne(x=>x.TradeDossier).WithMany(x=>x.Links).HasForeignKey(x=>x.TradeDossierId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class TradeAttachmentConfiguration:IEntityTypeConfiguration<TradeAttachment>{public void Configure(EntityTypeBuilder<TradeAttachment>b){b.ToTable("RII_TRADE_ATTACHMENTS");b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>new{x.TradeDossierId,x.Sha256});b.Property(x=>x.OriginalFileName).HasMaxLength(255).IsRequired();b.Property(x=>x.StoredFileName).HasMaxLength(100).IsRequired();b.Property(x=>x.ContentType).HasMaxLength(100).IsRequired();b.Property(x=>x.Sha256).HasMaxLength(64).IsUnicode(false).IsRequired();b.Property(x=>x.DocumentNumber).HasMaxLength(80);}}
